/**
 * Location values.
 * @interface Location
 * @property {number} lat
 * @property {number} lng
 * @property {string} city
 * @property {string} state
 * @property {string} country
 * @property {string} timezone
 */
export interface Location {
    lat: number;
    lng: number;
    city: string;
    state: string;
    country: string;
    timezone: string;
}

/**
 * Time values.
 * @interface Time
 * @property {number} hour
 * @property {number} minute
 */
export interface Time {
    hour: number;
    minute: number;
}

