export type ErrorCode = 'UNEXPECTED' | 'UNAUTHORIZED' | 'INVALID_URL' | 'ECONNREFUSED' | 'WRITE_ERROR' | 'READ_ERROR' | 'ERROR';

/** Namespace for mapping error codes */
export namespace ErrorCode {
    export const INVALID_URL: ErrorCode = 'INVALID_URL';
    export const UNAUTHORIZED: ErrorCode = 'UNAUTHORIZED';
    export const UNEXPECTED: ErrorCode = 'UNEXPECTED';
    export const ECONNREFUSED: ErrorCode = 'ECONNREFUSED';
    export const WRITE_ERROR: ErrorCode = 'WRITE_ERROR';
    export const READ_ERROR: ErrorCode = 'READ_ERROR';
    export const ERROR: ErrorCode = 'ERROR';
}

export interface RequestError {
    code: ErrorCode;
    message: string;
}

export interface HttpResponse {
    statusCode: number;
    body: any;
}
