import * as service from '../service';
import * as nlu from '../nlu';
import * as asr from '../asr';
import * as skill from '../skill';
import * as proactive from '../proactive';
import * as common from '../common';
import { ResponseType } from './MessageType';
import { HubErrorCode } from './HubErrorCode';


export import MessageType = ResponseType;
export {
    HubErrorCode
};

export type Response<T extends ResponseType, D> = service.BaseResponse<T, D>;

export type SoSResponse = Response<MessageType.SOS, void>;
export type EoSResponse = Response<MessageType.EOS, void>;

export type ASRResponse = Response<MessageType.ASR, asr.ASRResult>;
export type NLUResponse = Response<MessageType.NLU, nlu.NLUResult>;


export interface ListenResponseData {
    asr: asr.ASRResult;
    nlu: nlu.NLUResult;
    match?: common.GlobalMatchResponseData;
}

export interface SkillRedirectData {
    match: common.GlobalMatchResponseData;
    memo?: any;
    asr?: asr.ASRResult;
    nlu?: nlu.NLUResult;
}

/**
 * A general state that the result of a listening turn represents.
 */
export enum ListenResultState {
    /**
     * No input was received - user did not say anything before we stopped listening.
     */
    noInput = 'noInput',
    /**
     * User said something, but it didn't match anything that we were listening for.
     */
    noMatch = 'noMatch',
    /**
     * User said something that matched what we were listening for. `nlu` can be expected to
     * exist and have valid data.
     */
    match = 'match'
}

/**
 * Class for wrapping ListenResponseData for less access depth and safer usage within skill code.
 */
export class ListenResult {
    asr: asr.ASRResult;
    nlu: nlu.NLUResult;
    match?: common.GlobalMatchResponseData;

    /**
     * Safe shorthand for the main ASR result.
     */
    get text(): string {
        return this.asr ? this.asr.text : '';
    }

    /**
     * Safe shorthand for the main NLU result, if any.
     */
    get intent(): string {
        return this.nlu ? this.nlu.intent : '';
    }

    /**
     * Safe shorthand for supplimentary NLU results, if any.
     */
    get entities(): nlu.Entities {
        return this.nlu && this.nlu.entities ? this.nlu.entities : {};
    }

    /**
     * Shorthand for what type of result this response represents.
     */
    get state(): ListenResultState {
        //if we have an NLU result that has content, then it is a match
        if (this.nlu && (this.nlu.intent || Object.keys(this.entities).length)) {
            return ListenResultState.match;
        }
        //if we lack an ASR result, then there was no input (aka timeout)
        if (!this.asr || !this.asr.text) {
            return ListenResultState.noInput;
        }
        //otherwise, we have an ASR result but no valid NLU result, so it is not a match at all
        return ListenResultState.noMatch;
    }

    constructor(asr: asr.ASRResult, nlu?: nlu.NLUResult, match?: common.GlobalMatchResponseData) {
        this.asr = asr;
        this.nlu = nlu;
        this.match = match;
    }

    toJSON(): ListenResponseData {
        return {
            asr: this.asr,
            nlu: this.nlu,
            match: this.match
        };
    }
}

export interface HubErrorData {
    message: string;
    code?: HubErrorCode;
}

export type ListenResponse = Response<MessageType.LISTEN, ListenResponseData>;
export type SkillRedirectResponse = Response<MessageType.SKILL_REDIRECT, SkillRedirectData>;
export type SkillActionResponse = Response<MessageType.SKILL_ACTION, skill.response.SkillActionData>;
export type ErrorResponse = Response<MessageType.ERROR, HubErrorData>;

// And this is the union type of all hub responses
export type HubResponse = SoSResponse | EoSResponse |
    ASRResponse | NLUResponse | ListenResponse | SkillRedirectResponse |
    proactive.ProactiveResponse | ErrorResponse | skill.response.SkillResponse;
