import { BaseResponse } from '../service';
import { data } from '../jibo';
import * as action from './action';
import * as analytics from './analytics';
import * as nlu from '../nlu';
import * as asr from '../asr';


export enum ResponseType {
    SKILL_ACTION = 'SKILL_ACTION',
    SKILL_REDIRECT = 'SKILL_REDIRECT',
    ERROR = 'ERROR',
}

export interface ActionData {
    action: action.Action;
    analytics?: analytics.AnalyticsData;
    final?: boolean;
    fireAndForget?: boolean;
}

export interface ErrorData {
    message: string;
}

export interface RedirectData {
    skillID: string;
    memo?: any;
    asr?: asr.ASRResult;
    nlu?: nlu.NLUResult;
}

export interface SkillContext {
    skill: data.SkillData;
}

export type SkillActionData = ActionData & SkillContext;
export type SkillRedirectData = RedirectData & SkillContext;
export type SkillErrorData = ErrorData & SkillContext;
export type SkillResponseData = SkillErrorData | SkillActionData;
export type BaseSkillResponse<T extends ResponseType, D> = BaseResponse<T, D>;

/** Valid skill response */
export type ActionResponse = BaseSkillResponse<ResponseType.SKILL_ACTION, SkillActionData>;
/** Valid skill response */
export type RedirectResponse = BaseSkillResponse<ResponseType.SKILL_REDIRECT, SkillRedirectData>;
/** Valid skill response */
export type ErrorResponse = BaseSkillResponse<ResponseType.ERROR, SkillErrorData>;

/** Union type of all skill responses */
export type SkillResponse = ActionResponse | RedirectResponse | ErrorResponse;
